"""Structural steel material."""

from typing import Optional

from structuralcodes.materials.basic import ElasticMaterial, ElasticPlasticMaterial


class Structural_steel:
    """
    structural steel class.
    Args:
        f_y: yield strength in MPa (float)
        E: modulus of elasticity in MPa (float)
        nu: Poisson's ratio (float)
    """

    def __init__(
        self,
        f_y: Optional[float] = None,
        E: Optional[float] = 200000,
        nu: float = 0.3,
        density: float = 7850,
        Eh: float = 0.0,
        eps_su: Optional[float] = None,
    ):
        if f_y is None or E is None:
            raise ValueError("Structural_steel requires `f_y` and `E`.")
        self.material_sc_ep = ElasticPlasticMaterial(
            E=E,
            fy=f_y,
            density=density,
            Eh=Eh,
            eps_su=eps_su,
        )

        self.material_sc_el = ElasticMaterial(
            E=E, density=density, ultimate_strain=f_y / E
        )

        self.material_analysis = self.material_sc_ep  # material for analysis purposes

        self.f_y = f_y
        self.nu = nu
        self.E = E
        self.density = density

    def set_analysis_constitutive_law(self, class_plate: int) -> None:
        """Return constitutive model by class: elastic for 3/4, EP for 1/2."""
        if class_plate in (3, 4):
            self.material_analysis = self.material_sc_el
        else:
            self.material_analysis = self.material_sc_ep
